    function showStatus(message, tone) {
        const node = document.getElementById('scene-status');
        if (!node) return;
        node.hidden = !message;
        node.textContent = message || '';
        if (tone) {
            node.dataset.tone = tone;
        } else {
            delete node.dataset.tone;
        }
    }

    function clampNumber(value, min, max, fallback) {
        const parsed = Number.parseFloat(value);
        if (Number.isNaN(parsed)) return fallback;
        return Math.min(max, Math.max(min, parsed));
    }

    function cloneValue(value) {
        return JSON.parse(JSON.stringify(value));
    }

    function sanitizeScreenContent(screenContent) {
        const source = screenContent && typeof screenContent === 'object'
            ? cloneValue(screenContent)
            : cloneValue(DEFAULT_SCREEN_CONTENT);

        Object.keys(source).forEach((screenName) => {
            const entry = source[screenName];
            if (!entry || !Array.isArray(entry.body)) return;
            entry.body = entry.body.map((line) => {
                if (typeof line !== 'string') return line;
                return line.replace(/^â€¢\s*/u, '- ');
            });
        });

        return source;
    }

    function normalizeSceneSettings(settings) {
        const source = settings || {};
        return {
            backgroundColor: /^#[0-9A-F]{6}$/i.test(source.backgroundColor)
                ? source.backgroundColor
                : DEFAULT_SCENE_SETTINGS.backgroundColor,
            fogDensity: clampNumber(source.fogDensity, 0, 1, DEFAULT_SCENE_SETTINGS.fogDensity),
            fogSpread: clampNumber(source.fogSpread, 5, 300, DEFAULT_SCENE_SETTINGS.fogSpread)
        };
    }

    function normalizeViewerSettings(settings) {
        return {
            enableOrbit: settings && typeof settings.enableOrbit === 'boolean'
                ? settings.enableOrbit
                : DEFAULT_VIEWER_SETTINGS.enableOrbit
        };
    }

    function normalizeSceneData(payload) {
        if (Array.isArray(payload)) {
            return {
                viewerSettings: cloneValue(DEFAULT_VIEWER_SETTINGS),
                sceneSettings: normalizeSceneSettings(),
                lights: cloneValue(DEFAULT_LIGHTS),
                camera: cloneValue(DEFAULT_CAMERA),
                screenContent: sanitizeScreenContent(DEFAULT_SCREEN_CONTENT),
                sceneObjects: payload
            };
        }

        return {
            viewerSettings: normalizeViewerSettings(payload && payload.viewerSettings),
            sceneSettings: normalizeSceneSettings(payload && payload.sceneSettings),
            lights: Array.isArray(payload && payload.lights) && payload.lights.length
                ? payload.lights
                : cloneValue(DEFAULT_LIGHTS),
            camera: payload && payload.camera ? payload.camera : cloneValue(DEFAULT_CAMERA),
            screenContent: sanitizeScreenContent(payload && payload.screenContent ? payload.screenContent : DEFAULT_SCREEN_CONTENT),
            sceneObjects: Array.isArray(payload && payload.sceneObjects) ? payload.sceneObjects : []
        };
    }

    function hasTextObjects(list) {
        return (Array.isArray(list) ? list : []).some(function (item) {
            return item.type === 'text' || (Array.isArray(item.children) && hasTextObjects(item.children));
        });
    }

